Let's start by creating the `parser.py` file with an initial structure to implement the Pratt parser. We'll define a class `Parser` and methods for handling different types of expressions.

{"name": "write_file", "arguments": {"path": "parser.py", "content": "#!/usr/bin/env python3

class Parser:
    def __init__(self, tokens):
        self.tokens = tokens
        self.tok_index = 0

    def parse(self):
        return self.expr()

    def expr(self):
        lhs = self.unary()
        while True:
            if self.match("+") or self.match("-"):
                op = self.token.type
                rhs = self.unary()
                lhs = (op, lhs, rhs)
            else:
                break
        return lhs

    def unary(self):
        if self.match("-"):
            op = self.token.type
            operand = self.primary()
            return (op, operand)
        else:
            return self.primary()

    def primary(self):
        if self.match("NUMBER"):
            return int(self.token.literal)
        elif self.match("IDENTIFIER"):
            return self.token.text
        elif self.match("("):
            expr = self.parse()
            self.consume(" ", "Expected ')' after expression")
            return expr

    def match(self, type_):
        if self.check(type_):
            self.advance()
            return True
        return False

    def check(self, type_):
        if self.is_at_end():
            return False
        t = self.peek()
        return t.type == type_

    def advance(self):
        if not self.is_at_end():
            self.tok_index += 1
        return self.previous()

    def is_at_end(self):
        return self.tok_index >= len(self.tokens)

    def peek(self):
        return self.tokens[self.tok_index]

    def previous(self):
        return self.tokens[self.tok_index - 1]

    def consume(self, type_, message):
        if self.match(type_):
            return self.previous()
        raise Exception(message)
